#include "Helper.h"#include <iterator>#include <iostream>#include <fstream>#include <sstream>#include <memory>#include <stdexcept>#include "Book.h"#include "Movie.h"#include "Magazine.h"using namespace std;vector<string> split(const string& line, char delimiter) {    vector<string> parts;    string part;    stringstream ss(line);    while (getline(ss, part, delimiter)) {        parts.push_back(part);    }    return parts;}void loadItemsFromFile(const string& fileName, LibraryInventory& libraryInventory) {    ifstream inputFile(fileName);    if (!inputFile) {        cout << "Error: Could not open file " << fileName << endl;        return;    }    string fileContent(        (istreambuf_iterator<char>(inputFile)),        istreambuf_iterator<char>()    );    for (char& ch : fileContent) {        if (ch == '\r') {            ch = '\n';        }    }    stringstream fileStream(fileContent);    string line;    while (getline(fileStream, line)) {        if (line.empty()) {            continue;        }        vector<string> data = split(line, '|');        if (data.size() < 3) {            cout << "Error: Invalid line format. Missing basic fields:" << endl;            cout << line << endl;            continue;        }        string type = data[0];        int shelf;        int compartment;        try {            shelf = stoi(data[1]);            compartment = stoi(data[2]);        }        catch (const invalid_argument&) {            cout << "Error: Shelf or compartment is not a number:" << endl;            cout << line << endl;            continue;        }        catch (const out_of_range&) {            cout << "Error: Shelf or compartment number is too large:" << endl;            cout << line << endl;            continue;        }        if (type == "BOOK") {            if (data.size() != 9) {                cout << "Error: Invalid BOOK line. Expected 9 fields:" << endl;                cout << line << endl;                continue;            }            libraryInventory.addItem(                shelf,                compartment,                make_unique<Book>(                    data[3],                    data[4],                    data[5],                    data[6],                    data[7],                    data[8]                )            );        }        else if (type == "MOVIE") {            if (data.size() != 9) {                cout << "Error: Invalid MOVIE line. Expected 9 fields:" << endl;                cout << line << endl;                continue;            }            vector<string> actors = split(data[8], ',');            libraryInventory.addItem(                shelf,                compartment,                make_unique<Movie>(                    data[3],                    data[4],                    data[5],                    data[6],                    data[7],                    actors                )            );        }        else if (type == "MAGAZINE") {            if (data.size() != 8) {                cout << "Error: Invalid MAGAZINE line. Expected 8 fields:" << endl;                cout << line << endl;                continue;            }            libraryInventory.addItem(                shelf,                compartment,                make_unique<Magazine>(                    data[3],                    data[4],                    data[5],                    data[6],                    data[7]                )            );        }        else {            cout << "Error: Unknown item type: " << type << endl;        }    }}